    poems:[{title:"अब कैसे छूटे राम नाम रट लागी",text:"अब कैसे छूटे राम नाम रट लागी।\nप्रभु जी तुम चंदन हम पानी, जाकी अंग-अंग बास समानी।\nप्रभु जी तुम घन बन हम मोरा, जैसे चितवत चंद चकोरा।।",form:"Pad"}]
